import std/strutils
import atcoder/extra/numeric/float128

proc emit(
    index: int;
    aHigh, aLow, bHigh, bLow: uint64;
) =
  let
    a = fromBits(aHigh, aLow)
    b = fromBits(bHigh, bLow)
    quotientBits = toBits(a / b)

  echo "DIV\t", index, "\t",
    toHex(aHigh, 16), "\t",
    toHex(aLow, 16), "\t",
    toHex(bHigh, 16), "\t",
    toHex(bLow, 16), "\t",
    toHex(quotientBits.high, 16), "\t",
    toHex(quotientBits.low, 16)

